// Generated by OrchestKit Claude Plugin

/**
 * Coordination metrics emitter — M168 Phase 5 (#1915).
 *
 * Async, fire-and-forget write counters for the SQLite coordination layer
 * (sessions.db). Hooks call `incrementMetric()` on each write; it bumps an
 * in-process counter synchronously (O(1), no I/O) and schedules a single
 * `setImmediate` flush. The flush appends compact JSONL lines via async
 * `appendFile`, so it NEVER blocks the hook hot path.
 *
 * Process model mirrors telemetry-jsonl.ts: each CC hook is a short-lived Node
 * process; the Node event loop keeps it alive until the scheduled flush fires,
 * so we don't need a background process or a stream. If disk is slow or the
 * write fails, the counter is dropped and a single stderr line is emitted —
 * coordination correctness never depends on metrics landing.
 *
 * `/ork:telemetry-inspect` reads coordination-metrics.jsonl for write
 * throughput; live session/lock counts are queried directly against sessions.db.
 *
 * Opt-out: ORK_DISABLE_COORDINATION_METRICS=1.
 */

import { appendFile, mkdir } from 'node:fs/promises';
import { join } from 'node:path';
import { getHomeDir } from './paths.js';

/** Co-located with sessions.db / events.jsonl (~/.local/state/orchestkit). */
export const METRICS_DIR = join(getHomeDir(), '.local', 'state', 'orchestkit');
export const METRICS_PATH = join(METRICS_DIR, 'coordination-metrics.jsonl');

/** In-process counters, flushed and cleared on each setImmediate tick. */
const counters = new Map<string, number>();
let flushScheduled = false;

/**
 * Increment a coordination metric. Synchronous + allocation-light; the actual
 * disk write is deferred to a single setImmediate flush per tick.
 */
export function incrementMetric(metric: string, delta = 1): void {
  if (process.env.ORK_DISABLE_COORDINATION_METRICS === '1') return;
  counters.set(metric, (counters.get(metric) ?? 0) + delta);
  if (flushScheduled) return;
  flushScheduled = true;
  setImmediate(flushMetrics);
}

/** Append one JSONL line per counter, then reset. Best-effort, never throws. */
function flushMetrics(): void {
  flushScheduled = false;
  if (counters.size === 0) return;
  const ts = new Date().toISOString();
  const lines = Array.from(counters, ([metric, count]) => `${JSON.stringify({ ts, metric, count })}\n`).join('');
  counters.clear();
  void mkdir(METRICS_DIR, { recursive: true, mode: 0o700 })
    .then(() => appendFile(METRICS_PATH, lines, 'utf8'))
    .catch(() => {
      process.stderr.write('[orchestkit] coordination metric dropped (disk slow/unavailable)\n');
    });
}

/** Exposed for tests. */
export const __metricsInternals = { counters, flushMetrics };
