// Created: 2026-04-17

/**
 * Pre-Commit Test Gate — PreToolUse/Bash hook
 *
 * Usage analytics #4 friction point: Claude declares "done" but tests are
 * failing (23 'mostly_achieved' out of 40 tracked sessions, 58% partial
 * success rate). Claude commits without running tests after the last edit.
 *
 * This hook does NOT block commits — advisory only. It flags when the
 * staged changeset includes files edited more recently than the last
 * recorded test run. Lives alongside the existing pre-commit-quality-runner
 * (which runs lint/typecheck, not the full test suite).
 *
 * Two responsibilities:
 *  1. When the command is a test runner, record the completion timestamp
 *     to `.claude/state/last-test-run.json`.
 *  2. When the command is `git commit`, compare that timestamp against the
 *     mtime of staged files. If any staged file is newer, inject an
 *     advisory additionalContext.
 */

import { existsSync, readFileSync, statSync, mkdirSync } from 'node:fs';
import { dirname, join } from 'node:path';
import { execSync } from 'node:child_process';
import type { HookInput, HookResult, HookContext } from '../../types.js';
import { outputSilentSuccess, outputNotify, getField } from '../../lib/common.js';
import { atomicWriteSync } from '../../lib/atomic-write.js';
import { NOOP_CTX } from '../../lib/context.js';

const HOOK_NAME = 'pretool/bash/pre-commit-test-gate';

// Patterns that identify a test-runner invocation. Matched against the
// start of the command (allowing a leading cd/&&/;).
const TEST_COMMAND_RE =
  /(^|[&;|\s])(npm\s+(run\s+)?test\b|vitest\b|jest\b|pytest\b|bun\s+test\b|deno\s+test\b|cargo\s+test\b|go\s+test\b|rspec\b|phpunit\b)/;

// Match git commit at the start (allowing `cd foo && git commit ...`)
const GIT_COMMIT_RE = /(^|[&;|\s])git\s+commit\b/;

interface TestRunState {
  timestamp: number;
  command: string;
}

function getStatePath(projectDir: string): string {
  return join(projectDir, '.claude', 'state', 'last-test-run.json');
}

function recordTestRun(projectDir: string, command: string): void {
  try {
    const p = getStatePath(projectDir);
    mkdirSync(dirname(p), { recursive: true });
    const state: TestRunState = { timestamp: Date.now(), command };
    atomicWriteSync(p, JSON.stringify(state), 'utf8');
  } catch {
    // Best-effort: if we can't write state, we silently skip the gate later.
  }
}

function readLastTestRun(projectDir: string): TestRunState | null {
  try {
    const p = getStatePath(projectDir);
    if (!existsSync(p)) return null;
    return JSON.parse(readFileSync(p, 'utf8')) as TestRunState;
  } catch {
    return null;
  }
}

/**
 * Ask git for files staged for commit. Returns full paths relative to repo
 * root, or an empty array on any error.
 */
function stagedFiles(projectDir: string): string[] {
  try {
    const out = execSync('git diff --cached --name-only', {
      cwd: projectDir,
      encoding: 'utf8',
      timeout: 3000,
    }).trim();
    if (!out) return [];
    return out.split('\n').filter(Boolean);
  } catch {
    return [];
  }
}

/**
 * Returns the newest mtime across the given files, or 0 if none readable.
 */
function newestMtime(projectDir: string, files: string[]): number {
  let newest = 0;
  for (const f of files) {
    try {
      const full = join(projectDir, f);
      const s = statSync(full);
      if (s.mtimeMs > newest) newest = s.mtimeMs;
    } catch {
      // Missing (deleted) file — skip.
    }
  }
  return newest;
}

export function preCommitTestGate(input: HookInput, ctx: HookContext = NOOP_CTX): HookResult {
  const toolName = input.tool_name || '';
  if (toolName !== 'Bash') return outputSilentSuccess();

  const command = getField<string>(input, 'tool_input.command') || '';
  if (!command) return outputSilentSuccess();

  const projectDir = ctx.projectDir;

  // --- Timestamp test-runner invocations ------------------------------------
  if (TEST_COMMAND_RE.test(command)) {
    recordTestRun(projectDir, command);
    ctx.log(HOOK_NAME, `Recorded test run: ${command.slice(0, 80)}`);
    return outputSilentSuccess();
  }

  // --- Gate git commit ------------------------------------------------------
  if (!GIT_COMMIT_RE.test(command)) {
    return outputSilentSuccess();
  }

  const lastRun = readLastTestRun(projectDir);
  const staged = stagedFiles(projectDir);
  if (staged.length === 0) {
    // Nothing staged — let the commit proceed (will fail on its own if empty)
    return outputSilentSuccess();
  }

  const newest = newestMtime(projectDir, staged);
  if (newest === 0) return outputSilentSuccess();

  if (!lastRun) {
    // No recorded test run at all in this session
    return outputNotify(
      `About to commit ${staged.length} file(s), but no test run has been recorded this session. ` +
        `Consider running tests before committing. (Advisory — commit not blocked.)`,
      { prefix: 'pre-commit-test-gate', event: 'PreToolUse' },
    );
  }

  if (newest > lastRun.timestamp) {
    const ageMin = Math.round((newest - lastRun.timestamp) / 60000);
    return outputNotify(
      `${staged.length} staged file(s) were edited ${ageMin} minute(s) after the last test run. ` +
        `Consider re-running tests before committing — 58% of analyzed sessions that skipped this step ended "mostly achieved." (Advisory.)`,
      { prefix: 'pre-commit-test-gate', event: 'PreToolUse' },
    );
  }

  // Test run is fresher than all edits — clean commit.
  return outputSilentSuccess();
}

// Exports for testing
export {
  TEST_COMMAND_RE,
  GIT_COMMIT_RE,
  getStatePath,
  recordTestRun,
  readLastTestRun,
};
