/**
 * Skill activation-channel telemetry writer.
 *
 * Appends one row per Skill invocation to `.claude/logs/skill-channels.jsonl`,
 * tagged with the activation channel it fired through (main | subagent | chain |
 * background). Lets the activation matrix be computed from real telemetry rather
 * than static analysis of frontmatter references.
 *
 * Schema: see `SkillChannelEntry` / `isValidSkillChannelEntry` in telemetry-schemas.ts.
 * Best-effort and non-throwing — telemetry must never break a hook.
 */

import { existsSync, mkdirSync } from 'node:fs';
import { join, dirname } from 'node:path';
import { bufferWrite } from './analytics-buffer.js';
import type { SkillChannel } from './telemetry-schemas.js';

export const SKILL_CHANNELS_FILE = join('.claude', 'logs', 'skill-channels.jsonl');

export interface RecordSkillChannelInput {
  skill: string;
  channel: SkillChannel;
  parent?: string;
  sessionId?: string;
}

/**
 * Record a single channel-tagged skill invocation. No-ops on empty skill name
 * and swallows all I/O errors (buffered write, flushed on process exit).
 */
export function recordSkillChannel(projectDir: string, entry: RecordSkillChannelInput): void {
  if (!entry.skill) return;
  try {
    const file = join(projectDir, SKILL_CHANNELS_FILE);
    const dir = dirname(file);
    if (!existsSync(dir)) mkdirSync(dir, { recursive: true });
    const row: Record<string, unknown> = {
      ts: new Date().toISOString(),
      skill: entry.skill,
      channel: entry.channel,
    };
    if (entry.parent) row.parent = entry.parent;
    if (entry.sessionId) row.session_id = entry.sessionId;
    bufferWrite(file, `${JSON.stringify(row)}\n`);
  } catch {
    // Telemetry is best-effort — never throw from a hook.
  }
}
