/**
 * Dependency-Confusion Scanner Hook
 * Scans Write/Edit content for install references to unclaimed / non-existent
 * npm packages under trusted scopes (e.g. the bare `@anthropic-ai/claude`,
 * which does not exist — the real CLI is `@anthropic-ai/claude-code`).
 *
 * Why: copy-pasting such an install command lets an attacker who later publishes
 * the unclaimed name run arbitrary code on a user's machine (supply-chain /
 * dependency confusion). Origin: Blue Bear Security report (2026-06-04).
 *
 * Behavior: WARN-only (non-blocking additionalContext). The hard gate is the CI
 * test tests/security/test-dependency-confusion.sh; this hook is the real-time
 * nudge at authoring time. Unlike content-secret-scanner, it does NOT exclude
 * markdown — the original finding was IN a markdown skill rule.
 *
 * OWASP A06:2021 (Vulnerable & Outdated Components).
 * CC 2.1.7 Compliant.
 */

import type { HookInput, HookResult, HookContext } from '../../types.js';
import { outputSilentSuccess, outputWithContext } from '../../lib/common.js';
import { NOOP_CTX } from '../../lib/context.js';

// ---------------------------------------------------------------------------
// Denylist: unclaimed/non-existent packages under trusted scopes.
// Each entry matches the EXACT bare token — the trailing boundary `(?![\w.-])`
// ensures `@anthropic-ai/claude-code` and `@anthropic-ai/claude-agent-sdk`
// (real packages) are never flagged, only the bare `@anthropic-ai/claude`.
// ---------------------------------------------------------------------------

const DENIED_PACKAGES: Array<{ name: string; regex: RegExp; suggestion: string }> = [
  {
    name: '@anthropic-ai/claude',
    regex: /@anthropic-ai\/claude(?![\w.-])/,
    suggestion: '@anthropic-ai/claude-code',
  },
];

function scanForDeniedPackage(
  content: string,
): { name: string; suggestion: string } | null {
  for (const { name, regex, suggestion } of DENIED_PACKAGES) {
    if (regex.test(content)) return { name, suggestion };
  }
  return null;
}

/**
 * Scan Write/Edit content for dependency-confusion package references.
 */
export function dependencyConfusionScanner(
  input: HookInput,
  ctx: HookContext = NOOP_CTX,
): HookResult {
  const toolName = input.tool_name;
  const filePath = input.tool_input.file_path || '';

  let content = '';
  if (toolName === 'Write') {
    content = input.tool_input.content || '';
  } else if (toolName === 'Edit') {
    content = input.tool_input.new_string || '';
  }

  if (!content) return outputSilentSuccess();

  const finding = scanForDeniedPackage(content);
  if (!finding) {
    return outputSilentSuccess();
  }

  ctx.log(
    'dependency-confusion-scanner',
    `WARN: unclaimed package "${finding.name}" referenced in ${filePath || '(unknown)'}`,
  );

  return outputWithContext(
    `⚠️ Dependency-confusion risk: "${finding.name}" is an unclaimed/non-existent npm package. ` +
      `Use the real package "${finding.suggestion}", or an explicit local path (./pkg) if this is ` +
      `illustrative. Leaving an unclaimed name lets an attacker publish it and run code on users who ` +
      `copy this command. (CI guard: tests/security/test-dependency-confusion.sh)`,
  );
}
