/**
 * Cron Guard - PreToolUse Hook
 * Blocks CronCreate in CI/headless environments.
 *
 * Detection signals (any one triggers block):
 * - CLAUDE_CODE_DISABLE_CRON=1 (explicit opt-out)
 * - CI=true (GitHub Actions, GitLab CI, etc.)
 * - GITHUB_ACTIONS=true
 * - Non-interactive terminal (no TTY)
 */

import type { HookInput, HookResult, HookContext } from '../types.js';
import { outputSilentSuccess, outputBlock } from '../lib/common.js';
import { NOOP_CTX } from '../lib/context.js';

const HOOK_NAME = 'cron-guard';

/**
 * Detect if running in a CI or headless environment
 */
function isHeadlessOrCI(): string | null {
  if (process.env.CLAUDE_CODE_DISABLE_CRON === '1') {
    return 'CLAUDE_CODE_DISABLE_CRON=1';
  }
  if (process.env.CI === 'true') {
    return 'CI=true';
  }
  if (process.env.GITHUB_ACTIONS === 'true') {
    return 'GITHUB_ACTIONS=true';
  }
  if (process.env.GITLAB_CI === 'true') {
    return 'GITLAB_CI=true';
  }
  if (process.env.CODEBUILD_BUILD_ID) {
    return 'AWS CodeBuild detected';
  }
  return null;
}

/**
 * Block CronCreate in CI/headless environments
 */
export function cronGuard(input: HookInput, ctx: HookContext = NOOP_CTX): HookResult {
  if (input.tool_name !== 'CronCreate') {
    return outputSilentSuccess();
  }

  const reason = isHeadlessOrCI();
  if (reason) {
    ctx.log(HOOK_NAME, `Blocked CronCreate: ${reason}`);
    return outputBlock(`Cron creation blocked in CI/headless environment (${reason}). Use ScheduleWakeup for in-session polling instead.`);
  }

  return outputSilentSuccess();
}

export default cronGuard;
