/**
 * Cross-platform path utilities for TypeScript hooks
 *
 * Provides consistent path handling across Windows, macOS, and Linux.
 * All path construction uses path.join() for correct separators.
 * All temp directories use os.tmpdir() for platform awareness.
 */

import os from 'node:os';
import path from 'node:path';
import { safeIdentifier } from './safe-fs.js';

/**
 * Get the user's home directory (cross-platform)
 * Prefers explicit env vars, falls back to os.homedir()
 */
export function getHomeDir(): string {
  return process.env.HOME || process.env.USERPROFILE || os.homedir();
}

/**
 * Get the system temp directory (cross-platform)
 * Returns /tmp on Unix, C:\Users\X\AppData\Local\Temp on Windows
 */
export function getTempDir(): string {
  return os.tmpdir();
}

/**
 * Strip JSON-shaped values that have historically leaked from hook stdout
 * into env vars or input fields (#1250). Anything starting with `{` or `[`
 * collapses to the supplied fallback (default: '.').
 */
function stripJsonLeak(value: string | undefined, fallback = '.'): string {
  if (!value) return fallback;
  if (value.startsWith('{') || value.startsWith('[')) return fallback;
  return value;
}

/**
 * Get the project directory from environment.
 * Guards against JSON strings leaking from hook stdout (#1250).
 */
export function getProjectDir(): string {
  return stripJsonLeak(process.env.CLAUDE_PROJECT_DIR);
}

/**
 * Resolve a project directory from a caller-supplied candidate, falling back
 * through env then cwd. Every layer is guarded against JSON leaks (#1250).
 *
 * Use this anywhere a hook handler reaches for `process.env.CLAUDE_PROJECT_DIR`
 * or accepts a `projectDir` argument from upstream code.
 */
export function safeProjectDir(candidate?: string | null): string {
  if (candidate && !candidate.startsWith('{') && !candidate.startsWith('[')) {
    return candidate;
  }
  const env = stripJsonLeak(process.env.CLAUDE_PROJECT_DIR, '');
  if (env) return env;
  return process.cwd();
}

/**
 * Get the plugin root directory from environment.
 * Guards against JSON strings leaking from hook stdout (#1250).
 */
export function getPluginRoot(): string {
  const pluginRoot = stripJsonLeak(process.env.CLAUDE_PLUGIN_ROOT, '');
  if (pluginRoot) return pluginRoot;
  return getProjectDir();
}

/**
 * Get the plugin persistent data directory (CC 2.1.78)
 * CLAUDE_PLUGIN_DATA survives plugin updates; /plugin uninstall prompts before deleting.
 * Falls back to project .claude/memory for CC < 2.1.78.
 */
export function getPluginDataDir(): string | null {
  return process.env.CLAUDE_PLUGIN_DATA || null;
}

/**
 * Get the session storage base directory.
 * Prefers CLAUDE_PLUGIN_DATA (CC 2.1.78) for persistence across plugin updates.
 * Falls back to project-local .claude/memory for older CC versions.
 */
export function getSessionStorageDir(): string {
  const pluginData = getPluginDataDir();
  if (pluginData) {
    return path.join(pluginData, 'sessions');
  }
  return path.join(getProjectDir(), '.claude', 'memory', 'sessions');
}

/**
 * Get the analytics storage base directory.
 * Prefers CLAUDE_PLUGIN_DATA (CC 2.1.78) for persistence across plugin updates.
 * Falls back to project-local .claude/memory for older CC versions.
 */
export function getAnalyticsStorageDir(): string {
  const pluginData = getPluginDataDir();
  if (pluginData) {
    return path.join(pluginData, 'analytics');
  }
  return path.join(getProjectDir(), '.claude', 'memory', 'analytics');
}

/**
 * Get the log directory path (cross-platform)
 * Uses path.join() for correct separators on all platforms
 */
export function getLogDir(): string {
  if (process.env.CLAUDE_PLUGIN_ROOT) {
    return path.join(getHomeDir(), '.claude', 'logs', 'ork');
  }
  return path.join(getProjectDir(), '.claude', 'logs');
}

/**
 * Get the memory directory path (cross-platform)
 */
export function getMemoryDir(): string {
  return path.join(getProjectDir(), '.claude', 'memory');
}

/**
 * Get the coordination directory path (cross-platform)
 */
export function getCoordinationDir(): string {
  return path.join(getProjectDir(), '.claude', 'coordination');
}

/**
 * Get the session metrics file path (cross-platform)
 * Uses CLAUDE_METRICS_FILE env var if set (for test isolation), otherwise temp dir.
 */
export function getMetricsFile(): string {
  return process.env.CLAUDE_METRICS_FILE || path.join(getTempDir(), 'claude-session-metrics.json');
}

/**
 * Get the session error metrics file path (cross-platform)
 */
export function getSessionErrorsFile(): string {
  return process.env.CLAUDE_SESSION_ERRORS_FILE || path.join(getTempDir(), 'claude-session-errors.json');
}

/**
 * Get the session temp directory for a given session ID (cross-platform).
 * #1826: validate sessionId before interpolating into the path — historical
 * incidents created `/tmp/claude-session-{"continue":true,...}` directories
 * when an envelope leaked from upstream hook stdout into the session-id
 * field. Fall back to a fixed 'invalid' bucket so all corrupt writes
 * collapse into one quarantine dir instead of spawning many.
 */
export function getSessionTempDir(sessionId: string): string {
  const safe = safeIdentifier(sessionId, 'invalid');
  return path.join(getTempDir(), `claude-session-${safe}`);
}

/**
 * Get the active todos file path (cross-platform)
 */
export function getActiveTodosFile(): string {
  return path.join(getTempDir(), 'claude-active-todos.json');
}

/**
 * Get the read count temp file path (cross-platform)
 */
export function getReadCountFile(): string {
  return path.join(getTempDir(), 'claude-read-count');
}

/**
 * Normalize a path for consistent comparison
 * Converts backslashes to forward slashes and removes trailing slashes
 */
export function normalizePath(p: string): string {
  return path.normalize(p).replace(/\\/g, '/').replace(/\/$/, '');
}

/**
 * Check if a path is absolute
 */
export function isAbsolutePath(p: string): boolean {
  return path.isAbsolute(p);
}

/**
 * Join path segments (cross-platform)
 * Re-export for convenience
 */
export const joinPath = path.join;

/**
 * Get path separator for current platform
 */
export const pathSeparator = path.sep;
