/**
 * Git utilities for TypeScript hooks
 * Ported from hooks/_lib/common.sh git functions
 */

import { execFileSync } from 'node:child_process';
import { getProjectDir } from './common.js';
import { assertSafeGitArgs } from './sanitize-shell.js';

/**
 * Execute a git command safely (no shell — args passed as array).
 * Returns trimmed stdout on success, empty string on failure.
 */
export function gitExec(args: string[], cwd?: string, timeout = 10000): string {
  try {
    assertSafeGitArgs(args);
    return execFileSync('git', args, {
      cwd: cwd || getProjectDir(),
      encoding: 'utf8',
      timeout,
      stdio: ['pipe', 'pipe', 'pipe'], windowsHide: true,
    }).trim();
  } catch {
    return '';
  }
}

/**
 * Get the current git branch
 */
export function getCurrentBranch(projectDir?: string): string {
  const dir = projectDir || getProjectDir();
  try {
    return execFileSync('git', ['branch', '--show-current'], {
      cwd: dir,
      encoding: 'utf8',
      timeout: 5000,
      stdio: ['pipe', 'pipe', 'pipe'], windowsHide: true,
    }).trim();
  } catch {
    return 'unknown';
  }
}

/**
 * Get the list of protected branches for the current project.
 *
 * Configurable via ORCHESTKIT_PROTECTED_BRANCHES env var (comma-separated).
 * Set this in your project's ork.settings.json:
 *   "env": { "ORCHESTKIT_PROTECTED_BRANCHES": "main,master,dev,staging" }
 *
 * Default: ["main", "master"]
 * Note: "dev" is intentionally excluded from the default — it is too
 * opinionated. Add it explicitly if your workflow uses dev as a protected branch.
 */
export function getProtectedBranches(): string[] {
  const envVal = process.env.ORCHESTKIT_PROTECTED_BRANCHES;
  if (envVal?.trim()) {
    return envVal.split(',').map(b => b.trim()).filter(Boolean);
  }
  return ['main', 'master'];
}

/**
 * Check if the given branch (or current branch) is protected.
 * Protected branches block direct commits/pushes.
 * Configurable via ORCHESTKIT_PROTECTED_BRANCHES env var.
 *
 * Branch resolution:
 *   undefined → fall back to getCurrentBranch() (production default)
 *   ''        → treat as "unknown branch, don't protect" (NOOP_CTX in tests;
 *               also a safe default when git detection fails)
 *   <string>  → check directly
 */
export function isProtectedBranch(branch?: string): boolean {
  const currentBranch = branch === undefined ? getCurrentBranch() : branch;
  if (!currentBranch) return false;
  return getProtectedBranches().includes(currentBranch);
}

/**
 * Get the repository root directory
 */
export function getRepoRoot(projectDir?: string): string {
  const dir = projectDir || getProjectDir();
  try {
    return execFileSync('git', ['rev-parse', '--show-toplevel'], {
      cwd: dir,
      encoding: 'utf8',
      timeout: 5000,
      stdio: ['pipe', 'pipe', 'pipe'], windowsHide: true,
    }).trim();
  } catch {
    return dir;
  }
}

/**
 * Check if path is inside a git repository
 */
export function isGitRepo(projectDir?: string): boolean {
  const dir = projectDir || getProjectDir();
  try {
    execFileSync('git', ['rev-parse', '--git-dir'], {
      cwd: dir,
      encoding: 'utf8',
      timeout: 5000,
      stdio: ['pipe', 'pipe', 'pipe'], windowsHide: true,
    });
    return true;
  } catch {
    return false;
  }
}

/**
 * Get git status (short format)
 */
export function getGitStatus(projectDir?: string): string {
  const dir = projectDir || getProjectDir();
  try {
    return execFileSync('git', ['status', '--short'], {
      cwd: dir,
      encoding: 'utf8',
      timeout: 10000,
      stdio: ['pipe', 'pipe', 'pipe'], windowsHide: true,
    }).trim();
  } catch {
    return '';
  }
}

/**
 * Check if there are uncommitted changes
 */
export function hasUncommittedChanges(projectDir?: string): boolean {
  return getGitStatus(projectDir).length > 0;
}

/**
 * Count the number of dirty (modified/untracked) files
 */
export function getDirtyFileCount(projectDir?: string): number {
  const dir = projectDir || getProjectDir();
  try {
    const output = execFileSync('git', ['status', '--porcelain'], {
      cwd: dir,
      encoding: 'utf8',
      timeout: 3000,
      stdio: ['pipe', 'pipe', 'pipe'], windowsHide: true,
    });
    return output.trim().split('\n').filter(l => l.trim()).length;
  } catch {
    return 0;
  }
}

/**
 * Get the default branch (main or master)
 */
export function getDefaultBranch(projectDir?: string): string {
  const dir = projectDir || getProjectDir();
  try {
    // Check if 'main' exists
    execFileSync('git', ['rev-parse', '--verify', 'main'], {
      cwd: dir,
      encoding: 'utf8',
      timeout: 5000,
      stdio: ['pipe', 'pipe', 'pipe'], windowsHide: true,
    });
    return 'main';
  } catch {
    try {
      // Check if 'master' exists
      execFileSync('git', ['rev-parse', '--verify', 'master'], {
        cwd: dir,
        encoding: 'utf8',
        timeout: 5000,
        stdio: ['pipe', 'pipe', 'pipe'], windowsHide: true,
      });
      return 'master';
    } catch {
      return 'main'; // Default to main
    }
  }
}

/**
 * Extract issue number from branch name
 * Supports patterns like: issue/123-description, feature/123, fix-123
 */
export function extractIssueNumber(branch: string): number | null {
  // Match common patterns
  const patterns = [
    /issue\/(\d+)/i,
    /feature\/(\d+)/i,
    /fix\/(\d+)/i,
    /bug\/(\d+)/i,
    /feat\/(\d+)/i,
    /^(\d+)-/,
    /-(\d+)$/,
    /#(\d+)/,
  ];

  for (const pattern of patterns) {
    const match = branch.match(pattern);
    if (match) {
      return parseInt(match[1], 10);
    }
  }

  return null;
}

/**
 * Get list of staged files (ready to be committed)
 * Returns array of file paths
 */
export function getStagedFiles(projectDir?: string): string[] {
  const dir = projectDir || getProjectDir();
  try {
    const output = execFileSync('git', ['diff', '--cached', '--name-only'], {
      cwd: dir,
      encoding: 'utf8',
      timeout: 10000,
      stdio: ['pipe', 'pipe', 'pipe'], windowsHide: true,
    }).trim();
    return output ? output.split('\n').filter((f) => f.trim()) : [];
  } catch {
    return [];
  }
}

/**
 * Get list of staged source files filtered by diff status
 * @param filter - git diff-filter value (default: 'ACMR' = Added/Copied/Modified/Renamed)
 */
export function getStagedSourceFiles(filter = 'ACMR'): string[] {
  const dir = getProjectDir();
  // Validate filter against git diff-filter alphabet to prevent injection
  const sanitized = filter.replace(/[^ACDMRTUXBacdmrtuxb*]/g, '');
  if (!sanitized) return [];
  try {
    const output = execFileSync('git', ['diff', '--cached', '--name-only', `--diff-filter=${sanitized}`], {
      cwd: dir,
      encoding: 'utf8',
      timeout: 5000,
      stdio: ['pipe', 'pipe', 'pipe'], windowsHide: true,
    }).trim();
    return output ? output.split('\n').filter((f) => f.trim()) : [];
  } catch {
    return [];
  }
}

/**
 * Analyze staged files for atomicity
 * Returns an object describing the change characteristics
 */
export function analyzeStagedChanges(projectDir?: string): {
  files: string[];
  directories: Set<string>;
  extensions: Set<string>;
  hasTests: boolean;
  hasConfig: boolean;
  hasDocs: boolean;
  hasSource: boolean;
} {
  const files = getStagedFiles(projectDir);
  const directories = new Set<string>();
  const extensions = new Set<string>();
  let hasTests = false;
  let hasConfig = false;
  let hasDocs = false;
  let hasSource = false;

  for (const file of files) {
    // Extract top-level directory
    const parts = file.split('/');
    if (parts.length > 1) {
      directories.add(parts[0]);
      // Also track second-level for deeper analysis
      if (parts.length > 2) {
        directories.add(`${parts[0]}/${parts[1]}`);
      }
    }

    // Extension
    const ext = file.split('.').pop() || '';
    extensions.add(ext);

    // Classify file type
    if (/\.(test|spec)\.\w+$/.test(file) || /^tests?\//.test(file) || /__tests__\//.test(file)) {
      hasTests = true;
    } else if (/\.(md|mdx|txt|rst)$/.test(file) || /^docs?\//.test(file) || file === 'README.md') {
      hasDocs = true;
    } else if (
      /\.(json|ya?ml|toml|ini|cfg|env)$/.test(file) ||
      /config/i.test(file) ||
      file === 'package.json' ||
      file === 'tsconfig.json'
    ) {
      hasConfig = true;
    } else {
      hasSource = true;
    }
  }

  return { files, directories, extensions, hasTests, hasConfig, hasDocs, hasSource };
}

/**
 * Validate branch name format
 * Returns error message if invalid, null if valid
 */
export function validateBranchName(branch: string): string | null {
  // Skip validation for protected branches
  if (isProtectedBranch(branch)) {
    return null;
  }

  // Valid prefixes
  const validPrefixes = [
    'issue/',
    'feature/',
    'fix/',
    'bug/',
    'feat/',
    'chore/',
    'docs/',
    'refactor/',
    'test/',
    'ci/',
    'perf/',
    'style/',
    'release/',
    'hotfix/',
  ];

  const hasValidPrefix = validPrefixes.some((prefix) => branch.startsWith(prefix));
  if (!hasValidPrefix) {
    return `Branch name should start with a valid prefix: ${validPrefixes.join(', ')}`;
  }

  // Check for issue number in issue/ branches
  if (branch.startsWith('issue/') && !extractIssueNumber(branch)) {
    return 'issue/ branches should include an issue number (e.g., issue/123-description)';
  }

  return null;
}
