/**
 * Playground Presence Warner — PreToolUse/Bash hook
 *
 * The CI workflow `playground-check` (.github/workflows/ci.yml) hard-fails
 * any non-bot, non-automation PR that lacks `docs/<branch-slug>/*.html` OR
 * is missing the literal word "playground" in its body. This hook surfaces
 * the missing playground BEFORE push so we don't waste a CI cycle.
 *
 * Fires on:
 *   - `git push` (anything that pushes the current branch)
 *   - `gh pr create ...`
 *
 * Skips:
 *   - main / master / develop / dev branches
 *   - bot/automation prefixes (dependabot/, renovate/, release-please)
 *   - if `docs/<slug>/*.html` already exists
 *
 * Advisory only — does NOT block. Opt out with `ORK_DISABLE_PLAYGROUND_WARNER=1`.
 */

import { execSync } from 'node:child_process';
import { existsSync, readdirSync } from 'node:fs';
import { join } from 'node:path';
import type { HookInput, HookResult, HookContext } from '../../types.js';
import { outputSilentSuccess, getField } from '../../lib/common.js';
import { NOOP_CTX } from '../../lib/context.js';

const HOOK_NAME = 'pretool/bash/playground-presence-warner';

// Matches `git push` (with or without flags/args) and `gh pr create`
const PUSH_RE = /(^|[&;|\s])(git\s+push|gh\s+pr\s+create)(\s|$)/;

// Branches that are exempt (main + automation prefixes)
const EXEMPT_BRANCHES = new Set(['main', 'master', 'develop', 'dev']);
const EXEMPT_PREFIXES = ['dependabot/', 'renovate/', 'release-please'];

function getCurrentBranch(projectDir: string): string | null {
  try {
    const out = execSync('git branch --show-current', {
      cwd: projectDir,
      encoding: 'utf8',
      timeout: 1000,
      stdio: ['pipe', 'pipe', 'ignore'],
    }).trim();
    return out || null;
  } catch {
    return null;
  }
}

/**
 * Convert branch name to docs slug (matches CI logic):
 *   feat/m128-bundle-x → feat--m128-bundle-x
 */
function branchToSlug(branch: string): string {
  return branch.replace(/\//g, '--');
}

function hasPlayground(projectDir: string, slug: string): boolean {
  const dir = join(projectDir, 'docs', slug);
  if (!existsSync(dir)) return false;
  try {
    return readdirSync(dir).some(f => f.endsWith('.html'));
  } catch {
    return false;
  }
}

export function playgroundPresenceWarner(input: HookInput, ctx: HookContext = NOOP_CTX): HookResult {
  if (process.env.ORK_DISABLE_PLAYGROUND_WARNER === '1') return outputSilentSuccess();
  if (input.tool_name !== 'Bash') return outputSilentSuccess();

  const command = getField<string>(input, 'tool_input.command') || '';
  if (!PUSH_RE.test(command)) return outputSilentSuccess();

  const projectDir = ctx.projectDir;
  const branch = getCurrentBranch(projectDir);
  if (!branch) return outputSilentSuccess();

  // Skip exempt branches
  if (EXEMPT_BRANCHES.has(branch)) return outputSilentSuccess();
  if (EXEMPT_PREFIXES.some(prefix => branch.startsWith(prefix))) {
    return outputSilentSuccess();
  }

  const slug = branchToSlug(branch);
  if (hasPlayground(projectDir, slug)) {
    ctx.log(HOOK_NAME, `Branch ${branch} already has docs/${slug}/*.html — silent`);
    return outputSilentSuccess();
  }

  ctx.log(HOOK_NAME, `Warning: branch ${branch} missing docs/${slug}/*.html — CI will fail`);

  return {
    continue: true,
    hookSpecificOutput: {
      additionalContext:
        `[playground-presence-warner] Branch \`${branch}\` has no playground at ` +
        `\`docs/${slug}/\`. The CI \`playground-check\` job will reject this PR ` +
        `unless you add at least one HTML file there. Also include the word ` +
        `"playground" in the PR body. Quick fix: \`mkdir -p docs/${slug} && ` +
        `touch docs/${slug}/explorer.html\` then write the playground content. ` +
        `(Advisory — push not blocked. Opt out with ORK_DISABLE_PLAYGROUND_WARNER=1.)`,
    },
  };
}

// Testing exports
export { PUSH_RE, branchToSlug, hasPlayground, EXEMPT_BRANCHES, EXEMPT_PREFIXES };
