/**
 * Headless AskUserQuestion Responder (CC 2.1.85)
 *
 * When running in headless mode (CI=true or ORCHESTKIT_HEADLESS=1),
 * auto-selects the first/recommended option in AskUserQuestion calls
 * so skills like /ork:expect -y and /ork:review-pr don't stall.
 *
 * Uses CC 2.1.85's PreToolUse updatedInput + permissionDecision: "allow"
 * to satisfy AskUserQuestion without human interaction.
 *
 * Only fires when: CI=true || ORCHESTKIT_HEADLESS=1
 * Never fires in interactive sessions.
 */

import type { HookInput, HookResult , HookContext} from '../../types.js';
import { outputSilentSuccess } from '../../lib/common.js';
import { NOOP_CTX } from '../../lib/context.js';

interface AskUserQuestionInput {
  questions?: Array<{
    question: string;
    options?: Array<{
      label: string;
      description?: string;
    }>;
    multiSelect?: boolean;
  }>;
}

function isHeadless(): boolean {
  return (
    process.env.CI === 'true' ||
    process.env.ORCHESTKIT_HEADLESS === '1' ||
    process.env.GITHUB_ACTIONS === 'true'
  );
}

export default function headlessResponder(input: HookInput, ctx: HookContext = NOOP_CTX): HookResult {
  // Only activate in headless mode
  if (!isHeadless()) {
    return outputSilentSuccess();
  }

  const toolInput = input.tool_input as AskUserQuestionInput | undefined;
  if (!toolInput?.questions?.length) {
    return outputSilentSuccess();
  }

  // Auto-select first option for each question (typically "Recommended")
  const answers: Record<string, string | string[]> = {};

  for (const q of toolInput.questions) {
    if (q.options?.length) {
      if (q.multiSelect) {
        // For multi-select, select all options
        answers[q.question] = q.options.map(o => o.label);
      } else {
        // For single-select, pick the first (usually "Recommended")
        answers[q.question] = q.options[0].label;
      }
    }
  }

  ctx.log('headless-responder', `Auto-answering ${toolInput.questions.length} question(s) in headless mode`);

  // CC 2.1.85: Return updatedInput with permissionDecision to satisfy AskUserQuestion
  return {
    continue: true,
    suppressOutput: true,
    hookSpecificOutput: {
      hookEventName: 'PreToolUse',
      permissionDecision: 'allow',
      updatedInput: {
        ...toolInput,
        _headless_answers: answers,
      },
    },
  };
}
